window.__QUIZ_DATA__=[{"id":"theory>Biology>2011>PAPER II>PART I>1>a>i","subject":"Biology","year":"2011","type":"Theory","sub_label":"i","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"What is the effect of gravity on plant growth?","images":[],"marking_scheme":"Effect of gravity on plant growth  The (main) root grows down in response to gravity/positively geotropic; the (main) stem/shoot/grows/upwards away from gravity/negatively geotropic.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2011>PAPER II>PART I>1>a>ii","subject":"Biology","year":"2011","type":"Theory","sub_label":"ii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"Describe an experiment to demonstrate the effect of gravity on the root of plants.","images":[],"marking_scheme":"Experiment to demonstrate the effect of gravity on the roots of a plant  - Select three germinating bean seedlings/seeds on a moist/damp sawdust/wet blotting paper;  - Pin/keep one seedling in a horizontal position  - Place another seedling in a vertical position with the radicle pointing upwards;  - Place the third seedling vertically with the radicle pointing downwards to serve as control;  - After 2-3days, it will be observed that the radicle of the seedling placed horizontally bends/grows downwards;  - The radicle of seedling placed vertically bends/grows downwards;  - Indicating positive geotropism/positive response to gravity;  - The seedling placed vertically with radicle pointing downwards did not bend.    OR   - Take a clinostat and two bean seedings;  - Pin one seeding horizontally on damp/moist/wet/cotton wool/blotting paper attached to the cork of the clinostat;  - Pin the other seeding onto some damp/moist/wet cotton wool/blotting paper attached to the cotton tile;  - Start the motor of the clinostat;  - Observe the seedings after 8-10hrs;  - It will be observed that the radical of the seeding placed horizontally bends/grows down wards;  - Indicating/showing positive geotropism","marks":"7","difficulty":"2"},{"id":"theory>Biology>2011>PAPER II>PART I>1>b","subject":"Biology","year":"2011","type":"Theory","sub_label":"b","group":"","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"Explain how bitter taste is detected in humans.","images":[],"marking_scheme":"Detection of bitter taste in humans   - Taste buds are unevenly distributed on the surface of the tongue  - Taste buds for detecting bitterness are at the back/end of the tongue  - For a substance is dissolved in saliva, sensory cells at the end/back of the tongue are stimulated;  - Which pass impulses to the brain;  - Which interprets the taste as bitter.","marks":"5","difficulty":"2"},{"id":"theory>Biology>2011>PAPER II>PART I>1>c","subject":"Biology","year":"2011","type":"Theory","sub_label":"c","group":"","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"Copy and complete the table below on endocrine glands and their functions   S/NEndocrine glandsHormone producedFunction1Thyroid2Insulin3Development of secondary sexual characteristics of females","images":[],"marking_scheme":"Hormones of endocrine glands and their functions    S/NEndocrine glandsHormone producedFunction1ThyroidThyroxin(e)Influences growth/development; Regulates/controls rate of metabolism2PancreasInsulinControls blood sugar level/causes liver to convert glucose to glycogen3Ovary/ovariesOestrogenDevelopment of secondary sexual characteristics of females","marks":"6","difficulty":"2"},{"id":"theory>Biology>2011>PAPER II>PART I>2>a","subject":"Biology","year":"2011","type":"Theory","sub_label":"a","group":"","topic":"PLANT AND ANIMAL NUTRITION : ALIMENTARY SYSTEM","question":"Make a diagram, 8 - 10 cm long to show the relative position of the following organs in the mammalian gut.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Biology>2011>PAPER II>PART I>2>b>i","subject":"Biology","year":"2011","type":"Theory","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : DISEASES AND DISEASE CAUSING ORGANISMS","question":"List two diseases of the liver.","images":[],"marking_scheme":"Two diseases of the liver     - Liver cirrhosis  - Hepatitis  - Gall stones  - Amoebic liver abscess;  - Cancer/tumor of the liver;","marks":"2","difficulty":"1"},{"id":"theory>Biology>2011>PAPER II>PART I>2>b>ii","subject":"Biology","year":"2011","type":"Theory","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : DISEASES AND DISEASE CAUSING ORGANISMS","question":"State five effect of the disease in 2(b)(i) on the human body","images":[],"marking_scheme":"Effects of liver diseases on humans    - Loss of appetite   - Jaundice/yellowish eye/skin;   - Loss of weight  - (Slight) Fever;  - Abdominal pain;   - Weakness and tiredness  -  Headache  - Oedema/swollen abdomen/accumulation of fluid in the abdomen;","marks":"5","difficulty":"2"},{"id":"theory>Biology>2011>PAPER II>PART I>2>c","subject":"Biology","year":"2011","type":"Theory","sub_label":"c","group":"","topic":"PLANT AND ANIMAL NUTRITION : VITAMINS","question":"State the deficiency symptoms of the following vitamins;","images":[],"marking_scheme":"Deficiency Symptoms  Vitamin A   - Night blindness/poor vision  - Colds/bronchitis;  - Dry Scaly skin      Vitamin C  - Swollen joints/scurvy/bleeding gums/sore mouth;  - Low resistance to infection  - Dental disorders    Vitamin K   - Excessive bleeding/haemorrhage of wounds/inability of blood to clot","marks":"1","difficulty":"2"},{"id":"theory>Biology>2011>PAPER II>PART I>3>a>i","subject":"Biology","year":"2011","type":"Theory","sub_label":"i","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE","question":"State the second law of Thermodynamics","images":[],"marking_scheme":"Second Law of Thermodynamics    This states that when there is conversion of energy from one form to another, there is always a loss/decrease; in the amount of useful energy.","marks":"3","difficulty":"3"},{"id":"theory>Biology>2011>PAPER II>PART I>3>a>ii","subject":"Biology","year":"2011","type":"Theory","sub_label":"ii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"Use the second law of of thermodynamics to explain the flow of energy across different trophic levels in food chain","images":[],"marking_scheme":"Flow of energy across different levels in a food chain    - Transfer of energy between trophic levels;  - Is not 100% completely efficient;  - Successive levels have less energy;  - And support fewer organisms;  - And support fewer organisms;  - Primary producers/green plants have the highest energy;  - When herbivores/primary consumers feed on primary producers;   - The energy level is reduced;  - When carnivores/secondary consumers feed on herbivores;  - The energy level is further reduced;  - Part of the energy is lost as heat at each trophic level;  - Not all parts of the preceeding organisms are eaten by the predator/organism at the next trophic level;  - Energy is lost in the process of respiration/feeding/movement/metabolic activities.","marks":"8","difficulty":"3"},{"id":"theory>Biology>2011>PAPER II>PART I>3>b>i","subject":"Biology","year":"2011","type":"Theory","sub_label":"i","group":"","topic":"ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION","question":"State three factors that can likely limit the size of human populations.","images":[],"marking_scheme":"Factors that can limit human popullations  - Famine/scarcity of food  - diseases/epidemics;  - increased mortality/death rate by wars/natural disasters/correctly named disaster.  -  Emigration  - Increase mortality  - Reduced natality/birth rate","marks":"3","difficulty":"2"},{"id":"theory>Biology>2011>PAPER II>PART I>3>b>ii","subject":"Biology","year":"2011","type":"Theory","sub_label":"ii","group":"","topic":"ECOLOGICAL MANAGEMENT : ADAPTATION OF ORGANISMS TO HABITATS.","question":"Outline two ways each by which humans can overcome the factors named in 3(b)(i)","images":[],"marking_scheme":"Ways of overcoming the factors    Famine  - Availability of food (through improved farming technques);  - Mechanized farming  - Improved storage facilities;  - Use of fertilizers/agro chemials;  - Genetic engineering;  - Improved Planting materials/seeds/sterns etc.  - Improved finance.    Diseases  - Health care  - Immunization;  - Preventive drugs;  - Improved diet;  - Good sanitation.      Wars  - Improved/enhanced communication/dialogue  - Medication.  - Prohibition of illegal firarms  - Good goverance    Natural Disasters  - Study of the environment;  - Promote environmental friendly activities;  - Preservation of natural habitats.  - Accurate and promote forecast of disaster    Increased Mortality/death rate  - Provision of balanced/good diet  - Good medicare;  - Adequate security;  - Peaceful resolution of conflicts/prevention of wars;  - Effective management of disaster;    Emigration  - Provide adequate food/shelter  - Improved health/environment/sanitation  - Urbanization/development;    Reduced natality/Birth rate  - Apply birth control methods;  - Legislation against abortion;  - Education/awareness against sexual transmitted diseases (STD's)","marks":"14","difficulty":"2"},{"id":"theory>Biology>2011>PAPER II>PART I>4>a>i","subject":"Biology","year":"2011","type":"Theory","sub_label":"i","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"What is the different between the genotype and phenotype of an individual?","images":[],"marking_scheme":"Difference between genotype and phenotype  A person's genotype is the sum total of the person's genetic constitution; while the phenotype is the observed trait/physical characteristics","marks":"2","difficulty":"1"},{"id":"theory>Biology>2011>PAPER II>PART I>4>a>ii","subject":"Biology","year":"2011","type":"Theory","sub_label":"ii","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"State two factors each which determine each of the terms in 4(a)(i)","images":[],"marking_scheme":"Factors which determine genotype  - Genotype of parents  - Mutation    Factors which determine phenotype  - Genotype  - Environment  - Diet   - Health","marks":"2","difficulty":"2"},{"id":"theory>Biology>2011>PAPER II>PART I>4>b>i","subject":"Biology","year":"2011","type":"Theory","sub_label":"i","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)","question":"In a breeding experiment , a homozygous black dog (BB) was crossed with a homozygous white dog (bb) to produce black puppies  in the first filial generation (F1).  The second filial generation produce a total of (240) black and white puppies.    With the aid of genetic diagram, determine: the number of white puppies;","images":["data:image/png;base64,"],"marking_scheme":"Calculation  The number of white puppies using the phenotypic ratio 3 black 1 white = 240  Total No of puppies produced - 240    No of white puppies produce  = 1/4 x 240  60 white puppies    OR Calculation  No of white puppies 1/4 x 240 = 60","marks":"12","difficulty":"3"},{"id":"theory>Biology>2011>PAPER II>PART I>4>b>ii","subject":"Biology","year":"2011","type":"Theory","sub_label":"ii","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)","question":"In a breeding experiment , a homozygous black dog (BB) was crossed with a homozygous white dog (bb) to produce black puppies  in the first filial generation (F1).  The second filial generation produce a total of (240) black and white puppies.   With the aid of genetic diagram, determine: the number of black puppies in the second filial generation","images":["data:image/png;base64,"],"marking_scheme":"Calculation  Number of black puppies   = 3/4 x 240  180 black puppies     OR Calculation  No of black puppies 3/4 x 240 =180","marks":"2","difficulty":"3"},{"id":"theory>Biology>2011>PAPER II>PART II>5>6>a>i","subject":"Biology","year":"2011","type":"Theory","sub_label":"i","group":"","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"What is cross pollination?","images":[],"marking_scheme":"Cross pollination is the transfer of pollen grains from the anthers to the stigma of another flower of the same or allied species by pollination agents.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2011>PAPER II>PART II>5>6>a>ii","subject":"Biology","year":"2011","type":"Theory","sub_label":"ii","group":"","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"In a tabular form state four differences between wind-pollinated flowers and insect pollinated flowers.","images":[],"marking_scheme":"Wind pollinated flower  Insect pollunated flower1. The flowers are small the flowers are large2. Petals are dull and inconspicuous Petals are brightly coloured and conspicuous 3. No nectar produced  Nectar produced 4. Produced large quantity of pollen grains  Produce a small quantity of pollen grains5. Pollen grains are smooth/not sticky  Pollen grains are rough/sticky6. Pollen grains are light Pollen grains are heavy 7. Petals are not scented  Petals are scented 8. Stigma not sticky  Stigma sticky","marks":"3","difficulty":"3"},{"id":"theory>Biology>2011>PAPER II>PART II>5>6>a>iii","subject":"Biology","year":"2011","type":"Theory","sub_label":"iii","group":"","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Explain four ways on which flowers are adapted for cross pollination","images":[],"marking_scheme":"- Unisexuality is when either the stamen or stigma only is present on a plant(i.e flowers with only one productive organ)  - Dichogamy is the maturity of stamens and stigma of a bisexual flower at different times.  - Self-sterility is the situation whereby the pollen grains of a flower on the same plant have no fertilizing effect on the stigma of the same flower.  -. Heterostyly/position of stigmas and anthers occurs in some erect flowers where the stigmas are kept higher than the stamen so that a visiting insect reaches the stigma before the anthers","marks":"3","difficulty":"2"},{"id":"theory>Biology>2011>PAPER II>PART II>5>6>b","subject":"Biology","year":"2011","type":"Theory","sub_label":"b","group":"","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"Make a diagram 8 - 10cm long of a longitudinal section of a human molar and label fully.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"4","difficulty":"3"},{"id":"theory>Biology>2011>PAPER II>PART II>5>a","subject":"Biology","year":"2011","type":"Theory","sub_label":"a","group":"","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"List three component of a light microscope and state their functions","images":[],"marking_scheme":"-. Objective lens - Magnifies objects to produce a real image of the object.  - Ocular lens or eyepiece - Acts a magnifying glass for the image produced by the objective, producing a final,  much larger virtual image.  - Low power objective - Used first in order to obtain a general view of the specimen.  - Fine adjust - Used to move objective lens to focus the object under high power.  - Coarse adjustment - Use to move body tube with low power objective","marks":"2","difficulty":"1"},{"id":"theory>Biology>2011>PAPER II>PART II>5>b>i","subject":"Biology","year":"2011","type":"Theory","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"Define the following terms and give one example in each case:    stimullants;","images":[],"marking_scheme":"Stimulants are drugs which increases the mental activity of the brain and nervous system to make a person more alert and awake. Examples are amphetamine, caffeine, nicotine and cocaine.","marks":"1","difficulty":"2"},{"id":"theory>Biology>2011>PAPER II>PART II>5>b>ii","subject":"Biology","year":"2011","type":"Theory","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"Define the following terms and give one example in each Case.","images":[],"marking_scheme":"Hallucinogens are drugs that initiate visual images that are sensed in the mind but which do not actually exist. Examples are LSD, cannabis and ecstasy.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2011>PAPER II>PART II>5>c","subject":"Biology","year":"2011","type":"Theory","sub_label":"c","group":"","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"State two effect of the substance in 5(b)(i) and (ii) on the human body","images":[],"marking_scheme":"Stimulant Effects  - Excitation  -  Nausea  - Irritability  - Mental disorder      Hallicinogens cause**    - Changes in perception  - Anxiety  - Hallucinations  - Panic","marks":"2","difficulty":"2"},{"id":"theory>Biology>2011>PAPER II>PART II>5>d","subject":"Biology","year":"2011","type":"Theory","sub_label":"d","group":"","topic":"CONCEPT OF LIVING : NERVOUS COORDINATION","question":"Why is it dangerous to drive after drinking?","images":[],"marking_scheme":"It is dangerous to drive after drinking alcohol because it is depresses and reduces the activity of the brain and nervous system. It causes reduced alertness, stupor and loss of control. In this state, accident are more probable to occur.","marks":"1","difficulty":"2"},{"id":"theory>Biology>2011>PAPER II>PART III>7>a>i","subject":"Biology","year":"2011","type":"Theory","sub_label":"i","group":"","topic":"MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION","question":"Explain the following terms:    Putrefaction","images":[],"marking_scheme":"A process by which agents of decay/saprophytic/purifying bacteria/fungi; decompose/breakdown; dead organic remains/waste products of other organisms; into ammonium compounds/nitrates","marks":"3","difficulty":"2"},{"id":"theory>Biology>2011>PAPER II>PART III>7>a>ii","subject":"Biology","year":"2011","type":"Theory","sub_label":"ii","group":"","topic":"PLANT AND ANIMAL NUTRITION : NITROGEN CYCLE","question":"Explain the following terms:  Nitrogen fixation","images":[],"marking_scheme":"The process by which free atmospheric nitrogen; is converted to nitrate in the soil; by thunder storm/bacteria in root noddles of legumes/soil","marks":"3","difficulty":"2"},{"id":"theory>Biology>2011>PAPER II>PART III>7>a>iii","subject":"Biology","year":"2011","type":"Theory","sub_label":"iii","group":"","topic":"PLANT AND ANIMAL NUTRITION : NITROGEN CYCLE","question":"Explain the following terms:  Nitrification","images":[],"marking_scheme":"The conversion of ammonia/ammonium compounds; to nitrites; then to nitrates; by nitrifying bacteria","marks":"3","difficulty":"2"},{"id":"theory>Biology>2011>PAPER II>PART III>7>a>iv","subject":"Biology","year":"2011","type":"Theory","sub_label":"iv","group":"","topic":"PLANT AND ANIMAL NUTRITION : NITROGEN CYCLE","question":"Explain the following terms:  Denitrification","images":[],"marking_scheme":"This is the conversion of nitrates; in the soil to atmospheric nitrogen; by denitrifying bacteria/fungi","marks":"3","difficulty":"2"},{"id":"theory>Biology>2011>PAPER II>PART III>7>b","subject":"Biology","year":"2011","type":"Theory","sub_label":"b","group":"","topic":"PLANT AND ANIMAL NUTRITION : NITROGEN CYCLE","question":"State three differences between Nitrogen fixation and Denitrification.","images":[],"marking_scheme":"Differences between Nitrogen Fixation and Denitrification    Nitrogen FixationDenitrificationFree atmospheric nitrogen is added to the soilNitrates in the soil is converted into atmospheric nitrogen;Nitrogen fixing bacteria are involvedDenitrifying bacteria are involved; It involves symbiotic and non-symbiotic organism/bacteriaPurely non-symbiotic organism/bacteriaModerate soil temperature is requiredHigh temperature is required.","marks":"3","difficulty":"3"},{"id":"theory>Biology>2011>PAPER II>PART III>7>c","subject":"Biology","year":"2011","type":"Theory","sub_label":"c","group":"","topic":"PLANT AND ANIMAL NUTRITION : NITROGEN CYCLE","question":"Explain how nitrogen from urine gets to the root of the plants","images":[],"marking_scheme":"How Nitrogen from Urine gets to the roots of plants    - When a person passes urine in the soil;  - Ammonium compound/urea present in urine; is converted into nitrite;  - By nitrifying bacteria/nitrosomonas;  - The nitrites are oxidized to nitrates;  - By other nitrifying bacteria/nitrobacter;  - Roots of plants absorb the nitrates.","marks":"5","difficulty":"3"},{"id":"theory>Biology>2011>PAPER II>PART III>8>a>i","subject":"Biology","year":"2011","type":"Theory","sub_label":"i","group":"","topic":"MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH","question":"What is immunity?","images":[],"marking_scheme":"Immunity    Immunity is the ability of the body to resist infection/disease; by producing antibodies.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2011>PAPER II>PART III>8>a>ii","subject":"Biology","year":"2011","type":"Theory","sub_label":"ii","group":"","topic":"MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH","question":"Explain two ways by which a person becomes immune to yellow fever","images":[],"marking_scheme":"Yellow Fever Immunity    Naturally Acquired Immunity   If one suffers from yellow fever; the person's body produces antibodies; which remain in the body to combat any reoccurrence of such a disease/yellow fever in the future.    Artificially Acquired Immunity  Vaccines made from mild strains of yellow fever viruses; are injected into the person's body vaccinated; this stimulates the person's body to produce the necessary antibodies which will prevent the invasion of stronger strains od yellow fever.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2011>PAPER II>PART III>8>a>iii","subject":"Biology","year":"2011","type":"Theory","sub_label":"iii","group":"","topic":"MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH","question":"Name four diseases for which babies are immunised","images":[],"marking_scheme":"Diseases for which babies are immunized    Diphtheria (DPT), Whooping cough (Pertussis), Tetanus, Polio/Poliomyelitis, Tuberculosis, Measles","marks":"4","difficulty":"2"},{"id":"theory>Biology>2011>PAPER II>PART III>8>b>i","subject":"Biology","year":"2011","type":"Theory","sub_label":"i","group":"","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"What is Translocation","images":[],"marking_scheme":"Translocation   This is the movement of sugar/food materials of photosynthesis; through a network of cells/sieve tubes/phloem; from the site of photosynthesis; the sites where they are utilized/growing regions of the plants/stored.","marks":"1","difficulty":"1"},{"id":"theory>Biology>2011>PAPER II>PART III>8>c>i","subject":"Biology","year":"2011","type":"Theory","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"State three differences  between the transport systems in flowering plants and mammals.","images":[],"marking_scheme":"Differences between transport systems in plants and animals    FeaturesPlantsAnimalsMediumMedium of transport is waterMedium of transport is blood;Transport vesselsTransport vessel is of non living cellsTransport vessel is of living cellsSubstances transportedOnly food substances transportedFood substances and wastes productsMechanismMechanism is as a result of transpiration osmosis etcMechanism is through the pumping of the heart.Environmental factorsTransport depends on environmental factors e.g. Wind temperature etcTransport does not depend on environmental factors.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2011>PAPER II>PART III>8>c>ii","subject":"Biology","year":"2011","type":"Theory","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"State three similarities  between the transport systems in flowering plants and mammals","images":[],"marking_scheme":"Similarities     - Made up of two types of vessels;  - Transported substances do not mix;  - Fluid medium.","marks":"3","difficulty":"2"}];